/* ==========================================================================
   MARKER CLUSTERING ENGINE
   Groups markers by grid cell so map doesnt crash loading 1500+ pins at once.
   Only renders pins visible in the current viewport + zoom level.
   ========================================================================== */
const ClusterEngine = {
  gridSize: 0.5,
  allSpots: [],
  init(spots) {
    this.allSpots = spots;
  },
  getVisibleSpots(bounds, zoom) {
    const sw = bounds.getSouthWest();
    const ne = bounds.getNorthEast();
    const filtered = this.allSpots.filter(s =>
      s.lat >= sw.lat && s.lat <= ne.lat &&
      s.lng >= sw.lng && s.lng <= ne.lng
    );
    if (zoom >= 10) return filtered;
    if (zoom >= 7) return this.clusterByGrid(filtered, 0.3);
    if (zoom >= 5) return this.clusterByGrid(filtered, 1.0);
    return this.clusterByGrid(filtered, 3.0);
  },
  clusterByGrid(spots, cellSize) {
    const cells = {};
    spots.forEach(s => {
      const key = Math.floor(s.lat / cellSize) + ',' + Math.floor(s.lng / cellSize);
      if (!cells[key]) {
        cells[key] = { items: [], lat: 0, lng: 0 };
      }
      cells[key].items.push(s);
      cells[key].lat += s.lat;
      cells[key].lng += s.lng;
    });
    const result = [];
    Object.values(cells).forEach(cell => {
      if (cell.items.length === 1) {
        result.push(cell.items[0]);
      } else {
        const avgLat = cell.lat / cell.items.length;
        const avgLng = cell.lng / cell.items.length;
        result.push({
          id: 'cluster-' + Math.floor(avgLat*100) + '-' + Math.floor(avgLng*100),
          title: cell.items.length + ' Campsites in Area',
          category: 'cluster',
          type: 'cluster',
          lat: avgLat,
          lng: avgLng,
          land_manager: 'Multiple',
          overnight_rule: 'Zoom in for details',
          verified: true,
          description: cell.items.length + ' verified camping locations in this area. Zoom in to see individual sites. Includes: ' + cell.items.slice(0, 3).map(i => i.title).join(', ') + (cell.items.length > 3 ? '...' : ''),
          author: { name: 'VanLyfa Cluster', avatar: 'avatar_gov' },
          vouches: cell.items.length,
          _isCluster: true,
          _clusterCount: cell.items.length
        });
      }
    });
    return result;
  }
};